Here's a function that accurately counts the number of times each word appears on separate lines in a given text:

```r
count_word_lines <- function(text) {
  lines <- split(text, split = "\n")

  # Split each text line into individual word entries
  word_lines <- lapply(lines, function(line) {
    words <- unlist(stringsplit(line))
    words[which(nchar(words) >= 1)] # Keep only non-empty words
  })

  # Count occurrences of each word across all lines
  word_freq <- table(unlist(lapply(word_lines, function(words) {
    counts <- count(lapply(strsplit(words, "\\s+"), function(x) sum(sapply(c('hello', 'dog'), is.numeric(x)))))
    return(counts))
  }))

  # Return the word counts in a clean format
  word_df <- as.data.table(word_freq)
  word_display <- rownames(word_df)
  return(as.character(word_display))
}

